@import "tailwindcss";

:root {
  --background: #ffffff;
  --foreground: #0a0b09;

  --wave-ink: #0a0b09;
  --wave-paper: #ffffff;
  --wave-cream: #f7f6f2;
  --wave-mist: #f0efe9;
  --wave-line: #e7e5dd;
  --wave-muted: #6b6a62;

  --wave-lime: #d7ff3d;
  --wave-lime-deep: #9fbf2e;
  --wave-teal: #3fb8a6;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);

  --color-wave-ink: var(--wave-ink);
  --color-wave-paper: var(--wave-paper);
  --color-wave-cream: var(--wave-cream);
  --color-wave-mist: var(--wave-mist);
  --color-wave-line: var(--wave-line);
  --color-wave-muted: var(--wave-muted);
  --color-wave-lime: var(--wave-lime);
  --color-wave-lime-deep: var(--wave-lime-deep);
  --color-wave-teal: var(--wave-teal);

  --font-sans: var(--font-poppins);
}

html {
  scroll-behavior: smooth;
}

body {
  background: var(--background);
  color: var(--foreground);
  font-family: var(--font-poppins), Arial, Helvetica, sans-serif;
}

.grain-overlay {
  background-image: var(--grain-url, url("/images/wave/grain.png"));
  background-repeat: repeat;
  background-size: 220px 220px;
}

::selection {
  background: var(--wave-lime);
  color: var(--wave-ink);
}

@keyframes marquee {
  from {
    transform: translateX(0);
  }
  to {
    transform: translateX(-50%);
  }
}

.animate-marquee {
  animation: marquee 28s linear infinite;
  width: max-content;
}

.line-clamp-2 {
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

