import Link from "next/link";
import { ReactNode } from "react";

type Props = {
  href: string;
  children: ReactNode;
  variant?: "dark" | "light" | "lime" | "outline-light";
  className?: string;
};

const VARIANTS: Record<string, string> = {
  dark: "bg-wave-ink text-white hover:bg-wave-lime hover:text-wave-ink",
  light: "bg-white text-wave-ink hover:bg-wave-lime",
  lime: "bg-wave-lime text-wave-ink hover:bg-wave-ink hover:text-white",
  "outline-light": "border border-white/40 text-white hover:bg-white hover:text-wave-ink",
};

export function Button({ href, children, variant = "dark", className = "" }: Props) {
  return (
    <Link
      href={href}
      className={`inline-flex items-center justify-center gap-2 rounded-full px-8 py-3.5 text-sm font-semibold tracking-wide transition-colors duration-300 ${VARIANTS[variant]} ${className}`}
    >
      {children}
    </Link>
  );
}

"use client";

import { useState } from "react";
import { supabase } from "@/lib/supabase";

export function ContactForm() {
  const [status, setStatus] = useState<"idle" | "loading" | "done" | "error">("idle");
  const [form, setForm] = useState({ name: "", email: "", message: "" });

  const onSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus("loading");
    const { error } = await supabase.from("contact_messages").insert(form);
    setStatus(error ? "error" : "done");
  };

  if (status === "done") {
    return (
      <div className="rounded-2xl bg-wave-cream p-10 text-center">
        <h3 className="text-2xl font-bold mb-2">Message sent.</h3>
        <p className="text-wave-muted">We&rsquo;ll get back to you shortly.</p>
      </div>
    );
  }

  return (
    <form onSubmit={onSubmit} className="grid grid-cols-1 gap-5">
      <input
        required
        placeholder="Your name"
        className="rounded-xl border border-wave-line bg-white px-5 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-wave-lime"
        value={form.name}
        onChange={(e) => setForm({ ...form, name: e.target.value })}
      />
      <input
        required
        type="email"
        placeholder="Email"
        className="rounded-xl border border-wave-line bg-white px-5 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-wave-lime"
        value={form.email}
        onChange={(e) => setForm({ ...form, email: e.target.value })}
      />
      <textarea
        required
        placeholder="How can we help?"
        rows={6}
        className="rounded-xl border border-wave-line bg-white px-5 py-4 text-sm focus:outline-none focus:ring-2 focus:ring-wave-lime resize-none"
        value={form.message}
        onChange={(e) => setForm({ ...form, message: e.target.value })}
      />
      {status === "error" ? (
        <p className="text-sm text-red-600">Something went wrong — please try again.</p>
      ) : null}
      <button
        type="submit"
        disabled={status === "loading"}
        className="rounded-full bg-wave-ink text-white px-8 py-4 text-sm font-semibold tracking-wide hover:bg-wave-lime hover:text-wave-ink transition-colors disabled:opacity-50"
      >
        {status === "loading" ? "Sending…" : "Send message"}
      </button>
    </form>
  );
}

import Link from "next/link";
