const IMAGES = [
  "amber-fall.jpg",
  "green-blur.jpg",
  "streak.jpg",
  "diagonal-glow.jpg",
  "neon-graffiti.jpg",
  "green-silhouette.jpg",
];

function imageForSeed(seed: string) {
  let hash = 0;
  for (let i = 0; i < seed.length; i++) hash = (hash * 31 + seed.charCodeAt(i)) >>> 0;
  return IMAGES[hash % IMAGES.length];
}

type EventCardData = {
  id: string;
  slug: string;
  title: string;
  start_time: string;
  min_price: number | null;
  currency: string;
  venue?: { name: string; city?: { name: string } | null } | null;
};

export function EventCard({ event }: { event: EventCardData }) {
  const date = new Date(event.start_time);
  const dateLabel = date.toLocaleDateString("en-GB", { weekday: "short", day: "numeric", month: "short" });
  const timeLabel = date.toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" });

  return (
    <Link href={`/events`} className="group block">
      <div className="relative aspect-[3/4] overflow-hidden rounded-2xl bg-wave-mist">
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img
          src={asset(`/images/wave/${imageForSeed(event.slug)}`)}
          alt={event.title}
          className="absolute inset-0 h-full w-full object-cover transition-transform duration-700 group-hover:scale-105"
        />
        <div className="absolute inset-0 grain-overlay opacity-30 mix-blend-overlay" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/10 to-transparent" />
        <div className="absolute bottom-0 left-0 right-0 p-6 text-white">
          <div className="text-[11px] uppercase tracking-[0.15em] text-white/70 mb-2">
            {dateLabel} · {timeLabel}
          </div>
          <div className="text-xl font-bold leading-tight mb-1">{event.title}</div>
          <div className="text-sm text-white/70">{event.venue?.name}</div>
        </div>
      </div>
      <div className="flex items-center justify-between mt-3 px-1">
        <span className="text-sm text-wave-muted">{event.venue?.city?.name ?? "Split"}</span>
        <span className="text-sm font-semibold">
          {event.min_price ? `From €${Number(event.min_price).toFixed(0)}` : "Free"}
        </span>
      </div>
    </Link>
  );
}

