import { supabase } from "./supabase";

export type WebsiteEvent = {
  id: string;
  slug: string;
  title: string;
  description: string | null;
  start_time: string;
  min_price: number | null;
  currency: string;
  genres: string[] | null;
  venue: { name: string; slug: string; city: { name: string } | null } | null;
};

export type WebsiteVenue = {
  id: string;
  name: string;
  slug: string;
  description: string | null;
  capacity: number | null;
  instagram_handle: string | null;
  city: { name: string; country: string } | null;
};

const LAUNCH_CITY = "Split";

// WAVE launches first in Split — surface it ahead of other cities already seeded
// in the backend, without hiding them (they're future-expansion markets, not deleted).
function byLaunchCityFirst<T extends { city?: { name: string } | null }>(a: T, b: T) {
  const aFirst = a.city?.name === LAUNCH_CITY;
  const bFirst = b.city?.name === LAUNCH_CITY;
  if (aFirst === bFirst) return 0;
  return aFirst ? -1 : 1;
}

export async function fetchUpcomingEvents(limit = 6): Promise<WebsiteEvent[]> {
  const { data, error } = await supabase
    .from("events")
    .select(
      `
      id, slug, title, description, start_time, min_price, currency, genres,
      venue:venues ( name, slug, city:cities ( name ) )
    `
    )
    .eq("status", "published")
    .order("start_time")
    .limit(Math.max(limit * 4, 24));
  if (error) throw error;
  const events = (data ?? []) as unknown as WebsiteEvent[];
  return events.sort((a, b) => byLaunchCityFirst({ city: a.venue?.city }, { city: b.venue?.city })).slice(0, limit);
}

export async function fetchVenues(limit = 12): Promise<WebsiteVenue[]> {
  const { data, error } = await supabase
    .from("venues")
    .select(
      `
      id, name, slug, description, capacity, instagram_handle,
      city:cities ( name, country )
    `
    )
    .order("name")
    .limit(Math.max(limit * 3, 24));
  if (error) throw error;
  const venues = (data ?? []) as unknown as WebsiteVenue[];
  return venues.sort(byLaunchCityFirst).slice(0, limit);
}

